// Combinar todas las predicciones en un solo array
const items = $input.all();
const todasLasPredicciones = [];

for (const item of items) {
  if (item && item.json) {
    todasLasPredicciones.push(item.json);
  }
}

// Deduplicar por Evento
const seen = new Set();
const unique = todasLasPredicciones.filter(p => {
  if (!p.Evento || seen.has(p.Evento)) return false;
  seen.add(p.Evento);
  return true;
});

return unique.map(p => ({ json: p }));

const items = $input.all();
const destacadas = [];

for (const item of items) {
  const riesgo = item.json.Riesgo;
  const prob = parseFloat(item.json.Probabilidad_Victoria);
  if (riesgo === 'Bajo' && prob > 60) {
    destacadas.push(item);
  }
}

// Si no hay destacadas, devolvemos un placeholder
if (destacadas.length === 0) {
  return [{ json: {
    Evento: 'NO HAY APUESTAS DESTACADAS',
    Liga_Categoria: '-',
    Analisis_Forma: '-',
    Prediccion_Marcador: '-',
    Mercado: '-',
    Probabilidad_Victoria: '0%',
    Riesgo: '-',
    Justificacion_Clave: 'Ningún partido cumplió con Riesgo Bajo y Probabilidad > 60%',
    Fecha_Reporte: new Date().toISOString().slice(0,10)
  }}];
}

return destacadas;

